module binary_counter(clk, reset, load_en, data_in, count_out);
  input clk, reset, load_en;
  input [3:0] data_in;
  output reg [3:0] count_out;

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (reset) begin
      count_out <= 4'b0;
    end else if (load_en) begin
      count_out <= data_in;
    end else begin
      count_out <= count_out + 1;
    end
  end
endmodule
